const ig = $('generate-instagram').item.json;
const tw = $('generate-twitter').item.json;
const tt = $('generate-tiktok').item.json;

const getText = (r) => r?.content?.[0]?.text ?? '(error generando contenido)';

return [{
  json: {
    instagram: getText(ig),
    twitter: getText(tw),
    tiktok: getText(tt)
  }
}];
